{
  "sentences": [
    {
      "text": "我每天早上七點起床。",
      "pinyin": "Wǒ měitiān zǎoshang qī diǎn qǐchuáng.",
      "pinyin_numeric": "wo3 mei3tian1 zao3shang4 qi1 dian3 qi3chuang2",
      "translation_en": "I get up at seven every morning.",
      "translation_ko": "저는 매일 아침 7시에 일어납니다."
    },
    {
      "text": "他中午十二點吃午餐。",
      "pinyin": "Tā zhōngwǔ shí'èr diǎn chī wǔcān.",
      "pinyin_numeric": "ta1 zhong1wu3 shi2'er4 dian3 chi1 wu3can1",
      "translation_en": "He eats lunch at twelve noon.",
      "translation_ko": "그는 정오 12시에 점심을 먹습니다."
    },
    {
      "text": "我們晚上八點看電視。",
      "pinyin": "Wǒmen wǎnshang bā diǎn kàn diànshì.",
      "pinyin_numeric": "wo3men wan3shang4 ba1 dian3 kan4 dian4shi4",
      "translation_en": "We watch TV at eight in the evening.",
      "translation_ko": "우리는 저녁 8시에 텔레비전을 봅니다."
    },
    {
      "text": "她昨天下午三點去公園散步。",
      "pinyin": "Tā zuótiān xiàwǔ sān diǎn qù gōngyuán sànbù.",
      "pinyin_numeric": "ta1 zuo2tian1 xia4wu3 san1 dian3 qu4 gong1yuan2 san4bu4",
      "translation_en": "She went to the park for a walk at three yesterday afternoon.",
      "translation_ko": "그녀는 어제 오후 3시에 공원에 산책하러 갔습니다."
    },
    {
      "text": "我明天上午九點上班。",
      "pinyin": "Wǒ míngtiān shàngwǔ jiǔ diǎn shàngbān.",
      "pinyin_numeric": "wo3 ming2tian1 shang4wu3 jiu3 dian3 shang4ban1",
      "translation_en": "I go to work at nine tomorrow morning.",
      "translation_ko": "저는 내일 오전 9시에 출근합니다."
    },
    {
      "text": "他每天下午五點下班。",
      "pinyin": "Tā měitiān xiàwǔ wǔ diǎn xiàbān.",
      "pinyin_numeric": "ta1 mei3tian1 xia4wu3 wu3 dian3 xia4ban1",
      "translation_en": "He gets off work at five every afternoon.",
      "translation_ko": "그는 매일 오후 5시에 퇴근합니다."
    },
    {
      "text": "我們今天早上八點上課。",
      "pinyin": "Wǒmen jīntiān zǎoshang bā diǎn shàngkè.",
      "pinyin_numeric": "wo3men jin1tian1 zao3shang4 ba1 dian3 shang4ke4",
      "translation_en": "We have class at eight this morning.",
      "translation_ko": "우리는 오늘 아침 8시에 수업을 듣습니다."
    },
    {
      "text": "她昨天晚上十點睡覺。",
      "pinyin": "Tā zuótiān wǎnshang shí diǎn shuìjiào.",
      "pinyin_numeric": "ta1 zuo2tian1 wan3shang4 shi2 dian3 shui4jiao4",
      "translation_en": "She went to sleep at ten last night.",
      "translation_ko": "그녀는 어젯밤 10시에 잠을 잤습니다."
    },
    {
      "text": "我每天中午十二點休息。",
      "pinyin": "Wǒ měitiān zhōngwǔ shí'èr diǎn xiūxi.",
      "pinyin_numeric": "wo3 mei3tian1 zhong1wu3 shi2'er4 dian3 xiu1xi5",
      "translation_en": "I take a rest at twelve every noon.",
      "translation_ko": "저는 매일 정오 12시에 휴식합니다."
    },
    {
      "text": "他明天晚上七點看電影。",
      "pinyin": "Tā míngtiān wǎnshang qī diǎn kàn diànyǐng.",
      "pinyin_numeric": "ta1 ming2tian1 wan3shang4 qi1 dian3 kan4 dian4ying3",
      "translation_en": "He will watch a movie at seven tomorrow evening.",
      "translation_ko": "그는 내일 저녁 7시에 영화를 볼 것입니다."
    }
  ]
}
